mapper.sql:
WHERE station = #{station}
  AND DATE_FORMAT(datetime, '%Y-%m-%d %H:%i:00') >= #{startDateTime}
AND DATE_FORMAT(datetime, '%Y-%m-%d %H:%i:59') <= #{endDateTime}
AND temperature >= #{startTemperature}
AND temperature <= #{endTemperature}
AND humidity >= #{startHumidity}
AND humidity <= #{endHumidity}
AND speed >= #{startSpeed}
AND speed <= #{endSpeed}
AND direction >= #{startDirection}
AND direction <= #{endDirection}
AND rain >= #{startRain}
AND rain <= #{endRain}
AND sunlight >= #{startSunlight}
AND sunlight <= #{endSunlight}
AND pm25 >= #{startPm25}
AND pm25 <= #{endPm25}
AND pm10 >= #{startPm10}
AND pm10 <= #{endPm10}

mapper.select:
SELECT datetime, temperature, humidity, speed, direction, rain, sunlight, pm25, pm10
FROM ${tableName}

LIMIT #{pageSize} OFFSET #{offset}
